  1→// User / Creator
  2→export interface User {
  3→  id: string;
  4→  name: string;
  5→  email: string;
  6→  avatar?: string;
  7→  username: string;
  8→  bio: string;
  9→  plan: 'creator' | 'creator-pro';
 10→  stripeConnected: boolean;
 11→  paypalConnected: boolean;
 12→  socialLinks: {
 13→    instagram?: string;
 14→    tiktok?: string;
 15→    youtube?: string;
 16→    twitter?: string;
 17→    facebook?: string;
 18→    linkedin?: string;
 19→    pinterest?: string;
 20→  };
 21→  storeTheme: StoreTheme;
 22→  createdAt: string;
 23→}
 24→
 25→export interface StoreTheme {
 26→  template: 'minimal' | 'classic' | 'magazine' | 'bold';
 27→  primaryColor: string;
 28→  backgroundColor: string;
 29→  fontFamily: string;
 30→}
 31→
 32→// Products
 33→export type ProductType = 'digital' | 'course' | 'booking' | 'membership' | 'webinar' | 'link' | 'custom';
 34→
 35→export interface Product {
 36→  id: string;
 37→  title: string;
 38→  description: string;
 39→  type: ProductType;
 40→  price: number;
 41→  comparePrice?: number;
 42→  currency: string;
 43→  image?: string;
 44→  published: boolean;
 45→  downloads?: string[]; // for digital products
 46→  ctaText: string;
 47→  createdAt: string;
 48→  updatedAt: string;
 49→  salesCount: number;
 50→  revenue: number;
 51→}
 52→
 53→// Courses
 54→export interface Course {
 55→  id: string;
 56→  productId: string;
 57→  title: string;
 58→  description: string;
 59→  headerImage?: string;
 60→  modules: CourseModule[];
 61→  published: boolean;
 62→}
 63→
 64→export interface CourseModule {
 65→  id: string;
 66→  title: string;
 67→  lessons: CourseLesson[];
 68→  order: number;
 69→}
 70→
 71→export interface CourseLesson {
 72→  id: string;
 73→  title: string;
 74→  type: 'video' | 'text' | 'download';
 75→  content: string;
 76→  videoUrl?: string;
 77→  attachments?: string[];
 78→  order: number;
 79→  duration?: number; // minutes
 80→}
 81→
 82→// Bookings
 83→export interface BookingConfig {
 84→  id: string;
 85→  productId: string;
 86→  duration: number; // minutes
 87→  availability: WeeklyAvailability;
 88→  bufferBefore: number;
 89→  bufferAfter: number;
 90→  calendarConnected: boolean;
 91→}
 92→
 93→export interface WeeklyAvailability {
 94→  [day: string]: { start: string; end: string; enabled: boolean };
 95→}
 96→
 97→export interface Booking {
 98→  id: string;
 99→  productId: string;
100→  customerName: string;
101→  customerEmail: string;
102→  date: string;
103→  time: string;
104→  status: 'confirmed' | 'pending' | 'cancelled' | 'completed';
105→  notes?: string;
106→}
107→
108→// Memberships
109→export interface Membership {
110→  id: string;
111→  productId: string;
112→  interval: 'monthly' | 'yearly';
113→  benefits: string[];
114→  memberCount: number;
115→}
116→
117→// Orders / Transactions
118→export interface Order {
119→  id: string;
120→  productId: string;
121→  productTitle: string;
122→  customerName: string;
123→  customerEmail: string;
124→  amount: number;
125→  currency: string;
126→  status: 'completed' | 'refunded' | 'pending' | 'failed';
127→  paymentMethod: 'stripe' | 'paypal';
128→  createdAt: string;
129→}
130→
131→// Analytics
132→export interface AnalyticsData {
133→  period: string;
134→  views: number;
135→  uniqueVisitors: number;
136→  sales: number;
137→  revenue: number;
138→  conversionRate: number;
139→  topProducts: { name: string; sales: number; revenue: number }[];
140→  trafficSources: { source: string; visits: number; percentage: number }[];
141→  dailyData: { date: string; views: number; sales: number; revenue: number }[];
142→}
143→
144→// Email Marketing
145→export interface EmailFlow {
146→  id: string;
147→  name: string;
148→  trigger: 'purchase' | 'signup' | 'abandoned' | 'manual';
149→  subject: string;
150→  body: string;
151→  enabled: boolean;
152→  sentCount: number;
153→  openRate: number;
154→}
155→
156→export interface EmailBroadcast {
157→  id: string;
158→  subject: string;
159→  body: string;
160→  recipientCount: number;
161→  sentAt?: string;
162→  status: 'draft' | 'scheduled' | 'sent';
163→  openRate?: number;
164→  clickRate?: number;
165→}
166→
167→export interface Subscriber {
168→  id: string;
169→  email: string;
170→  name: string;
171→  tags: string[];
172→  subscribedAt: string;
173→  source: string;
174→}
175→
176→// Affiliates
177→export interface Affiliate {
178→  id: string;
179→  name: string;
180→  email: string;
181→  code: string;
182→  commission: number; // percentage
183→  totalSales: number;
184→  totalEarnings: number;
185→  status: 'active' | 'pending' | 'disabled';
186→}
187→
188→// Discount Codes
189→export interface DiscountCode {
190→  id: string;
191→  code: string;
192→  type: 'percentage' | 'fixed';
193→  value: number;
194→  usageLimit?: number;
195→  usageCount: number;
196→  expiresAt?: string;
197→  productIds?: string[]; // empty = all products
198→  active: boolean;
199→}
200→
201→// Integrations
202→export interface Integration {
203→  id: string;
204→  name: string;
205→  type: 'payment' | 'calendar' | 'email' | 'analytics' | 'social';
206→  connected: boolean;
207→  icon: string;
208→  description: string;
209→}
210→
211→// Store page (public)
212→export interface PublicStoreData {
213→  username: string;
214→  name: string;
215→  bio: string;
216→  avatar?: string;
217→  theme: StoreTheme;
218→  products: Product[];
219→  socialLinks: User['socialLinks'];
220→}
