 83→html, body, #root {
 84→  margin: 0; padding: 0; min-height: 100%;
 85→  background-color: var(--bg-base);
 86→  color: var(--text-primary);
 87→  font-family: 'Inter', system-ui, sans-serif;
 88→  line-height: 1.5;
 89→  -webkit-font-smoothing: antialiased;
 90→}
 91→
 92→::selection { background-color: var(--accent); color: white; }
 93→
 94→* { scrollbar-width: thin; scrollbar-color: var(--border-default) transparent; }
 95→::-webkit-scrollbar { width: 6px; height: 6px; }
 96→::-webkit-scrollbar-track { background: transparent; }
 97→::-webkit-scrollbar-thumb { background: var(--border-default); border-radius: 3px; }
 98→
 99→*:focus-visible { outline: 2px solid var(--accent); outline-offset: 2px; border-radius: 4px; }
100→
101→@keyframes fadeInUp { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
102→.page-enter { animation: fadeInUp 0.2s ease-out; }
103→@keyframes shimmer { 0% { background-position: -200% 0; } 100% { background-position: 200% 0; } }
104→.skeleton-shimmer {
105→  background: linear-gradient(90deg, var(--glass-surface) 25%, var(--glass-surface-hover) 50%, var(--glass-surface) 75%);
106→  background-size: 200% 100%;
107→  animation: shimmer 1.8s ease-in-out infinite;
108→}
109→.hover-lift { transition: transform 0.2s ease-out, box-shadow 0.2s ease-out; }
110→.hover-lift:hover { transform: translateY(-2px); box-shadow: 0 8px 25px -5px rgba(0,0,0,0.1); }
111→.press-effect:active { transform: scale(0.98); }
