 4→
 5→interface BadgeProps {
 6→  variant?: BadgeVariant;
 7→  children: React.ReactNode;
 8→  className?: string;
 9→}
10→
11→const variantClasses: Record<BadgeVariant, string> = {
12→  default:
13→    'bg-[var(--bg-elevated)] text-[var(--text-secondary)] border border-[var(--border-default)]',
