 1→import React from 'react';
 2→import { TrendingUp, TrendingDown } from 'lucide-react';
 3→import { Card } from './Card';
 4→
 5→interface StatsCardProps {
 6→  label: string;
 7→  value: string | number;
 8→  change?: number;
 9→  changeLabel?: string;
10→  icon?: React.ReactNode;
11→  className?: string;
12→}
13→
14→export function StatsCard({
15→  label,
16→  value,
17→  change,
18→  changeLabel,
19→  icon,
20→  className = '',
21→}: StatsCardProps) {
22→  const isPositive = change !== undefined && change >= 0;
23→  const isNegative = change !== undefined && change < 0;
24→
25→  return (
26→    <Card padding="md" className={className}>
27→      <div className="flex items-start justify-between">
28→        <div className="flex-1 min-w-0">
29→          <p className="text-sm text-[var(--text-secondary)] mb-1">{label}</p>
30→          <p className="text-2xl font-bold text-[var(--text-primary)] tracking-tight">
31→            {value}
32→          </p>
33→
34→          {change !== undefined && (
35→            <div className="flex items-center gap-1.5 mt-2">
36→              {isPositive && (
37→                <TrendingUp className="w-3.5 h-3.5 text-emerald-500" />
38→              )}
39→              {isNegative && (
40→                <TrendingDown className="w-3.5 h-3.5 text-red-500" />
41→              )}
42→              <span
43→                className={`text-xs font-medium ${
44→                  isPositive ? 'text-emerald-500' : 'text-red-500'
45→                }`}
46→              >
47→                {isPositive ? '+' : ''}
48→                {change}%
49→              </span>
50→              {changeLabel && (
51→                <span className="text-xs text-[var(--text-secondary)]">
52→                  {changeLabel}
53→                </span>
54→              )}
55→            </div>
56→          )}
57→        </div>
58→
59→        {icon && (
60→          <div className="w-10 h-10 rounded-lg bg-[var(--bg-elevated)] flex items-center justify-center shrink-0 ml-4">
61→            <span className="text-[var(--text-secondary)]">{icon}</span>
62→          </div>
63→        )}
64→      </div>
65→    </Card>
66→  );
67→}
68→

 1→import React from 'react';
 2→
 3→interface Column<T> {
 4→  key: string;
 5→  label: string;
 6→  render?: (value: unknown, row: T, index: number) => React.ReactNode;
 7→}
 8→
 9→interface DataTableProps<T extends Record<string, unknown>> {
10→  columns: Column<T>[];
11→  data: T[];
12→  onRowClick?: (row: T, index: number) => void;
13→  className?: string;
14→}
15→
16→export function DataTable<T extends Record<string, unknown>>({
17→  columns,
18→  data,
19→  onRowClick,
20→  className = '',
21→}: DataTableProps<T>) {
22→  return (
23→    <div
24→      className={`
25→        overflow-x-auto border border-[var(--border-default)] rounded-xl
26→        ${className}
27→      `.trim()}
28→    >
29→      <table className="w-full text-sm">
30→        <thead>
31→          <tr className="border-b border-[var(--border-default)]">
32→            {columns.map((col) => (
33→              <th
34→                key={col.key}
35→                className="px-4 py-3 text-left text-xs font-medium text-[var(--text-secondary)] uppercase tracking-wider bg-[var(--bg-elevated)]"
36→              >
37→                {col.label}
38→              </th>
39→            ))}
40→          </tr>
41→        </thead>
42→        <tbody>
43→          {data.map((row, rowIndex) => (
44→            <tr
45→              key={rowIndex}
46→              className={`
47→                border-b border-[var(--border-default)] last:border-b-0
48→                ${rowIndex % 2 === 1 ? 'bg-[var(--bg-elevated)]' : 'bg-[var(--bg-surface)]'}
49→                ${onRowClick ? 'cursor-pointer hover:bg-[var(--bg-elevated)]' : ''}
50→                transition-colors duration-100
51→              `.trim()}
52→              onClick={onRowClick ? () => onRowClick(row, rowIndex) : undefined}
53→            >
54→              {columns.map((col) => (
55→                <td
56→                  key={col.key}
57→                  className="px-4 py-3 text-[var(--text-primary)] whitespace-nowrap"
58→                >
59→                  {col.render
60→                    ? col.render(row[col.key], row, rowIndex)
61→                    : (row[col.key] as React.ReactNode)}
62→                </td>
63→              ))}
64→            </tr>
65→          ))}
66→
67→          {data.length === 0 && (
68→            <tr>
69→              <td
70→                colSpan={columns.length}
71→                className="px-4 py-12 text-center text-[var(--text-secondary)]"
72→              >
73→                No data available
74→              </td>
75→            </tr>
76→          )}
77→        </tbody>
78→      </table>
79→    </div>
80→  );
81→}
