 1→import React from 'react';
 2→
 3→interface Tab {
 4→  id: string;
 5→  label: string;
 6→}
 7→
 8→interface TabsProps {
 9→  tabs: Tab[];
10→  activeTab: string;
11→  onChange: (tabId: string) => void;
12→  className?: string;
13→}
14→
15→export function Tabs({ tabs, activeTab, onChange, className = '' }: TabsProps) {
16→  return (
17→    <div
18→      className={`
19→        flex gap-1 border-b border-[var(--border-default)]
20→        ${className}
21→      `.trim()}
22→      role="tablist"
23→    >
24→      {tabs.map((tab) => {
25→        const isActive = tab.id === activeTab;
26→
27→        return (
28→          <button
29→            key={tab.id}
30→            role="tab"
31→            aria-selected={isActive}
32→            onClick={() => onChange(tab.id)}
33→            className={`
34→              relative px-4 py-2.5 text-sm font-medium transition-colors duration-150
35→              ${
36→                isActive
37→                  ? 'text-[var(--accent)]'
38→                  : 'text-[var(--text-secondary)] hover:text-[var(--text-primary)]'
39→              }
40→            `.trim()}
41→          >
42→            {tab.label}
43→            {isActive && (
44→              <span className="absolute bottom-0 left-0 right-0 h-0.5 bg-[var(--accent)] rounded-full" />
45→            )}
46→          </button>
47→        );
48→      })}
49→    </div>
50→  );
51→}
