import React, { useState } from 'react';
import {
  Plus,
  Mail,
  Zap,
  ShoppingCart,
  UserPlus,
  ShoppingBag,
  Hand,
  ArrowRight,
  BarChart3,
  Edit2,
  Trash2,
  Send,
  Eye,
} from 'lucide-react';
import { Button } from '../components/ui/Button';
import { Card } from '../components/ui/Card';
import { Badge } from '../components/ui/Badge';
import { Toggle } from '../components/ui/Toggle';
import { demoEmailFlows } from '../lib/demo-data';
import type { EmailFlow } from '../types';

const triggerConfig: Record<
  EmailFlow['trigger'],
  { label: string; variant: 'accent' | 'success' | 'warning' | 'default'; icon: React.ElementType }
> = {
  purchase: { label: 'Purchase', variant: 'accent', icon: ShoppingCart },
  signup: { label: 'Signup', variant: 'success', icon: UserPlus },
  abandoned: { label: 'Abandoned', variant: 'warning', icon: ShoppingBag },
  manual: { label: 'Manual', variant: 'default', icon: Hand },
};

export default function EmailFlows() {
  const [flows, setFlows] = useState(demoEmailFlows);

  const handleToggle = (id: string) => {
    setFlows((prev) =>
      prev.map((f) => (f.id === id ? { ...f, enabled: !f.enabled } : f))
    );
  };

  return (
    <div className="page-enter space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-[var(--text-primary)]">Email Flows</h1>
          <p className="text-sm text-[var(--text-secondary)] mt-1">
            Automated email sequences triggered by customer actions
          </p>
        </div>
        <Button icon={<Plus className="w-4 h-4" />}>Create Flow</Button>
      </div>

      {/* Flow Cards */}
      <div className="space-y-4">
        {flows.map((flow) => {
          const config = triggerConfig[flow.trigger];
          const TriggerIcon = config.icon;

          return (
            <Card key={flow.id} padding="none" className="overflow-hidden">
              <div className="flex items-stretch">
                {/* Visual Flow Indicator */}
                <div className="hidden sm:flex items-center gap-2 px-5 py-5 border-r border-[var(--border-default)] bg-[var(--bg-elevated)]">
                  <div className="flex flex-col items-center gap-1.5">
                    <div className="w-9 h-9 rounded-lg bg-[var(--accent-subtle)] flex items-center justify-center">
                      <TriggerIcon className="w-4 h-4 text-[var(--accent-text)]" />
                    </div>
                    <span className="text-[10px] text-[var(--text-tertiary)] font-medium">Trigger</span>
                  </div>
                  <ArrowRight className="w-3.5 h-3.5 text-[var(--text-tertiary)] shrink-0" />
                  <div className="flex flex-col items-center gap-1.5">
                    <div className="w-9 h-9 rounded-lg bg-[var(--bg-surface)] border border-[var(--border-default)] flex items-center justify-center">
                      <Mail className="w-4 h-4 text-[var(--text-secondary)]" />
                    </div>
                    <span className="text-[10px] text-[var(--text-tertiary)] font-medium">Email</span>
                  </div>
                  <ArrowRight className="w-3.5 h-3.5 text-[var(--text-tertiary)] shrink-0" />
                  <div className="flex flex-col items-center gap-1.5">
                    <div className="w-9 h-9 rounded-lg bg-[var(--success-subtle)] flex items-center justify-center">
                      <BarChart3 className="w-4 h-4 text-[var(--success)]" />
                    </div>
                    <span className="text-[10px] text-[var(--text-tertiary)] font-medium">Stats</span>
                  </div>
                </div>

                {/* Flow Details */}
                <div className="flex-1 p-5">
                  <div className="flex items-start justify-between gap-4">
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2.5 mb-2">
                        <h3 className="text-base font-semibold text-[var(--text-primary)] truncate">
                          {flow.name}
                        </h3>
                        <Badge variant={config.variant}>{config.label}</Badge>
                      </div>

                      <p className="text-sm text-[var(--text-secondary)] mb-3 flex items-center gap-1.5">
                        <Mail className="w-3.5 h-3.5 shrink-0" />
                        <span className="truncate">{flow.subject}</span>
                      </p>

                      {/* Stats Row */}
                      <div className="flex items-center gap-5">
                        <div className="flex items-center gap-1.5 text-sm">
                          <Send className="w-3.5 h-3.5 text-[var(--text-tertiary)]" />
                          <span className="text-[var(--text-secondary)]">
                            <span className="font-medium text-[var(--text-primary)]">
                              {flow.sentCount.toLocaleString()}
                            </span>{' '}
                            sent
                          </span>
                        </div>
                        <div className="flex items-center gap-1.5 text-sm">
                          <Eye className="w-3.5 h-3.5 text-[var(--text-tertiary)]" />
                          <span className="text-[var(--text-secondary)]">
                            <span className="font-medium text-[var(--text-primary)]">
                              {flow.openRate}%
                            </span>{' '}
                            open rate
                          </span>
                        </div>
                      </div>
                    </div>

                    {/* Actions */}
                    <div className="flex items-center gap-3 shrink-0">
                      <Toggle
                        enabled={flow.enabled}
                        onChange={() => handleToggle(flow.id)}
                      />
                      <div className="flex items-center gap-1 border-l border-[var(--border-default)] pl-3">
                        <Button variant="ghost" size="sm" icon={<Edit2 className="w-3.5 h-3.5" />}>
                          Edit
                        </Button>
                        <Button variant="ghost" size="sm" icon={<Trash2 className="w-3.5 h-3.5" />} className="text-red-500 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-500/10">
                          Delete
                        </Button>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </Card>
          );
        })}
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import {
  Plus,
  Send,
  Eye,
  MousePointerClick,
  Users,
  Calendar,
  Clock,
  FileText,
} from 'lucide-react';
import { Button } from '../components/ui/Button';
import { Card } from '../components/ui/Card';
import { Badge } from '../components/ui/Badge';
import { demoEmailBroadcasts } from '../lib/demo-data';
import type { EmailBroadcast } from '../types';

const statusConfig: Record<
  EmailBroadcast['status'],
  { label: string; variant: 'success' | 'warning' | 'default' }
> = {
  sent: { label: 'Sent', variant: 'success' },
  scheduled: { label: 'Scheduled', variant: 'warning' },
  draft: { label: 'Draft', variant: 'default' },
};

function ProgressBar({ value, max = 100, color = 'accent' }: { value: number; max?: number; color?: string }) {
  const pct = Math.min((value / max) * 100, 100);
  const colorMap: Record<string, string> = {
    accent: 'bg-[var(--accent)]',
    success: 'bg-emerald-500',
    warning: 'bg-amber-500',
  };

  return (
    <div className="flex items-center gap-3">
      <div className="flex-1 h-2 rounded-full bg-[var(--bg-elevated)] overflow-hidden">
        <div
          className={`h-full rounded-full transition-all duration-500 ${colorMap[color] || colorMap.accent}`}
          style={{ width: `${pct}%` }}
        />
      </div>
      <span className="text-xs font-medium text-[var(--text-secondary)] w-10 text-right">
        {value.toFixed(1)}%
      </span>
    </div>
  );
}

export default function Broadcasts() {
  const [subject, setSubject] = useState('');
  const [body, setBody] = useState('');
  const [scheduleEnabled, setScheduleEnabled] = useState(false);

  // Compute aggregate stats from sent broadcasts
  const sentBroadcasts = demoEmailBroadcasts.filter((b) => b.status === 'sent');
  const avgOpenRate =
    sentBroadcasts.length > 0
      ? sentBroadcasts.reduce((sum, b) => sum + (b.openRate || 0), 0) / sentBroadcasts.length
      : 0;
  const avgClickRate =
    sentBroadcasts.length > 0
      ? sentBroadcasts.reduce((sum, b) => sum + (b.clickRate || 0), 0) / sentBroadcasts.length
      : 0;
  const deliveryRate = 98.2; // Simulated

  return (
    <div className="page-enter space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-[var(--text-primary)]">Broadcasts</h1>
          <p className="text-sm text-[var(--text-secondary)] mt-1">
            One-time email campaigns to your subscriber list
          </p>
        </div>
        <Button icon={<Plus className="w-4 h-4" />}>New Broadcast</Button>
      </div>

      {/* Stats Overview */}
      {sentBroadcasts.length > 0 && (
        <Card padding="md">
          <h3 className="text-sm font-semibold text-[var(--text-primary)] mb-4">
            Campaign Performance
          </h3>
          <div className="space-y-3">
            <div>
              <div className="flex items-center justify-between mb-1.5">
                <span className="text-sm text-[var(--text-secondary)]">Delivery Rate</span>
                <span className="text-sm font-medium text-[var(--text-primary)]">{deliveryRate}%</span>
              </div>
              <ProgressBar value={deliveryRate} color="success" />
            </div>
            <div>
              <div className="flex items-center justify-between mb-1.5">
                <span className="text-sm text-[var(--text-secondary)]">Avg. Open Rate</span>
                <span className="text-sm font-medium text-[var(--text-primary)]">{avgOpenRate.toFixed(1)}%</span>
              </div>
              <ProgressBar value={avgOpenRate} color="accent" />
            </div>
            <div>
              <div className="flex items-center justify-between mb-1.5">
                <span className="text-sm text-[var(--text-secondary)]">Avg. Click Rate</span>
                <span className="text-sm font-medium text-[var(--text-primary)]">{avgClickRate.toFixed(1)}%</span>
              </div>
              <ProgressBar value={avgClickRate} color="warning" />
            </div>
          </div>
        </Card>
      )}

      {/* Broadcast List */}
      <div className="space-y-3">
        <h3 className="text-sm font-semibold text-[var(--text-secondary)] uppercase tracking-wider">
          Campaigns
        </h3>
        {demoEmailBroadcasts.map((broadcast) => {
          const config = statusConfig[broadcast.status];
          const sentDate = broadcast.sentAt
            ? new Date(broadcast.sentAt).toLocaleDateString('en-US', {
                month: 'short',
                day: 'numeric',
                year: 'numeric',
              })
            : null;

          return (
            <Card key={broadcast.id} hover padding="md">
              <div className="flex items-start justify-between gap-4">
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2.5 mb-2">
                    <h3 className="text-base font-semibold text-[var(--text-primary)] truncate">
                      {broadcast.subject}
                    </h3>
                    <Badge variant={config.variant}>{config.label}</Badge>
                  </div>

                  <div className="flex items-center gap-4 flex-wrap text-sm text-[var(--text-secondary)]">
                    <span className="flex items-center gap-1.5">
                      <Users className="w-3.5 h-3.5" />
                      {broadcast.recipientCount.toLocaleString()} recipients
                    </span>
                    {sentDate && (
                      <span className="flex items-center gap-1.5">
                        <Calendar className="w-3.5 h-3.5" />
                        {sentDate}
                      </span>
                    )}
                  </div>
                </div>

                {/* Metrics */}
                {broadcast.status === 'sent' && (
                  <div className="flex items-center gap-5 shrink-0">
                    <div className="text-center">
                      <div className="flex items-center gap-1 text-sm text-[var(--text-secondary)]">
                        <Eye className="w-3.5 h-3.5" />
                        <span>Opens</span>
                      </div>
                      <p className="text-lg font-bold text-[var(--text-primary)]">
                        {broadcast.openRate}%
                      </p>
                    </div>
                    <div className="text-center">
                      <div className="flex items-center gap-1 text-sm text-[var(--text-secondary)]">
                        <MousePointerClick className="w-3.5 h-3.5" />
                        <span>Clicks</span>
                      </div>
                      <p className="text-lg font-bold text-[var(--text-primary)]">
                        {broadcast.clickRate}%
                      </p>
                    </div>
                  </div>
                )}
              </div>
            </Card>
          );
        })}
      </div>

      {/* New Broadcast Form Concept */}
      <Card padding="lg">
        <h3 className="text-lg font-semibold text-[var(--text-primary)] mb-1">
          Compose New Broadcast
        </h3>
        <p className="text-sm text-[var(--text-secondary)] mb-5">
          Create a new email campaign to send to your subscribers
        </p>

        <div className="space-y-4">
          {/* Subject */}
          <div>
            <label className="block text-sm font-medium text-[var(--text-primary)] mb-1.5">
              Subject Line
            </label>
            <div className="relative">
              <FileText className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-[var(--text-tertiary)]" />
              <input
                type="text"
                value={subject}
                onChange={(e) => setSubject(e.target.value)}
                placeholder="Enter email subject..."
                className="w-full pl-10 pr-4 py-2.5 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-surface)] text-[var(--text-primary)] placeholder:text-[var(--text-tertiary)] focus:outline-none focus:ring-2 focus:ring-[var(--accent)] focus:border-transparent"
              />
            </div>
          </div>

          {/* Body */}
          <div>
            <label className="block text-sm font-medium text-[var(--text-primary)] mb-1.5">
              Email Body
            </label>
            <textarea
              value={body}
              onChange={(e) => setBody(e.target.value)}
              placeholder="Write your email content..."
              rows={6}
              className="w-full px-4 py-2.5 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-surface)] text-[var(--text-primary)] placeholder:text-[var(--text-tertiary)] focus:outline-none focus:ring-2 focus:ring-[var(--accent)] focus:border-transparent resize-none"
            />
          </div>

          {/* Recipients & Schedule */}
          <div className="flex items-center gap-6 pt-2">
            <div className="flex items-center gap-2 text-sm text-[var(--text-secondary)]">
              <Users className="w-4 h-4" />
              <span>
                Sending to{' '}
                <span className="font-semibold text-[var(--text-primary)]">1,580</span>{' '}
                subscribers
              </span>
            </div>

            <div className="flex items-center gap-2">
              <button
                onClick={() => setScheduleEnabled(!scheduleEnabled)}
                className={`flex items-center gap-1.5 px-3 py-1.5 text-sm rounded-lg border transition-colors ${
                  scheduleEnabled
                    ? 'border-[var(--accent)] bg-[var(--accent-subtle)] text-[var(--accent-text)]'
                    : 'border-[var(--border-default)] text-[var(--text-secondary)] hover:bg-[var(--bg-elevated)]'
                }`}
              >
                <Clock className="w-3.5 h-3.5" />
                Schedule
              </button>
            </div>
          </div>

          {scheduleEnabled && (
            <div className="pl-0 pt-1">
              <label className="block text-sm font-medium text-[var(--text-primary)] mb-1.5">
                Schedule Date & Time
              </label>
              <input
                type="datetime-local"
                className="px-4 py-2.5 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-surface)] text-[var(--text-primary)] focus:outline-none focus:ring-2 focus:ring-[var(--accent)] focus:border-transparent"
              />
            </div>
          )}

          {/* Actions */}
          <div className="flex items-center gap-3 pt-2">
            <Button icon={<Send className="w-4 h-4" />}>
              {scheduleEnabled ? 'Schedule Broadcast' : 'Send Now'}
            </Button>
            <Button variant="secondary">Save as Draft</Button>
          </div>
        </div>
      </Card>
    </div>
  );
}

import React, { useState } from 'react';
import {
  Plus,
  Copy,
  Check,
  Percent,
  DollarSign,
  Shuffle,
  Calendar,
  Package,
  Tag,
} from 'lucide-react';
import { Button } from '../components/ui/Button';
import { Card } from '../components/ui/Card';
import { Badge } from '../components/ui/Badge';
import { Toggle } from '../components/ui/Toggle';
import { DataTable } from '../components/ui/DataTable';
import { demoDiscountCodes, demoProducts } from '../lib/demo-data';
import type { DiscountCode } from '../types';

function UsageBar({ used, limit }: { used: number; limit?: number }) {
  if (!limit) {
    return (
      <span className="text-sm text-[var(--text-primary)]">{used} uses</span>
    );
  }

  const pct = Math.min((used / limit) * 100, 100);
  const isHigh = pct >= 80;

  return (
    <div className="flex items-center gap-2.5 min-w-[120px]">
      <div className="flex-1 h-2 rounded-full bg-[var(--bg-elevated)] overflow-hidden">
        <div
          className={`h-full rounded-full transition-all duration-500 ${
            isHigh ? 'bg-amber-500' : 'bg-[var(--accent)]'
          }`}
          style={{ width: `${pct}%` }}
        />
      </div>
      <span className="text-xs text-[var(--text-secondary)] whitespace-nowrap">
        {used}/{limit}
      </span>
    </div>
  );
}

function generateRandomCode(): string {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
  let result = '';
  for (let i = 0; i < 8; i++) {
    result += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return result;
}

export default function DiscountCodes() {
  const [codes, setCodes] = useState(demoDiscountCodes);
  const [copiedId, setCopiedId] = useState<string | null>(null);

  // Create code form state
  const [newCode, setNewCode] = useState('');
  const [codeType, setCodeType] = useState<'percentage' | 'fixed'>('percentage');
  const [codeValue, setCodeValue] = useState('');
  const [hasUsageLimit, setHasUsageLimit] = useState(false);
  const [usageLimit, setUsageLimit] = useState('');
  const [expiryDate, setExpiryDate] = useState('');
  const [selectedProduct, setSelectedProduct] = useState('all');

  const handleCopy = (code: string, id: string) => {
    navigator.clipboard.writeText(code);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const handleToggle = (id: string) => {
    setCodes((prev) =>
      prev.map((c) => (c.id === id ? { ...c, active: !c.active } : c))
    );
  };

  const formatValue = (code: DiscountCode) => {
    return code.type === 'percentage' ? `${code.value}%` : `$${code.value}`;
  };

  const getProductNames = (code: DiscountCode) => {
    if (!code.productIds || code.productIds.length === 0) return 'All Products';
    return code.productIds
      .map((pid) => {
        const product = demoProducts.find((p) => p.id === pid);
        return product?.title || pid;
      })
      .join(', ');
  };

  const formatExpiry = (expiresAt?: string) => {
    if (!expiresAt) return 'Never';
    const date = new Date(expiresAt);
    const now = new Date();
    const isExpired = date < now;
    return (
      <span className={isExpired ? 'text-red-500' : ''}>
