  const sources = demoAnalytics.trafficSources;
  const totalVisits = sources.reduce((sum, s) => sum + s.visits, 0);

  const pieData = sources.map((s) => ({
    name: s.source,
    value: s.visits,
    color: SOURCE_COLORS[s.source] || '#64748B',
  }));

  const generatedUrl = useMemo(() => {
    const baseUrl = 'https://sarahcreates.stan.io';
    const params = new URLSearchParams();
    if (utmSource) params.set('utm_source', utmSource);
    if (utmMedium) params.set('utm_medium', utmMedium);
    if (utmCampaign) params.set('utm_campaign', utmCampaign);
    const queryString = params.toString();
    return queryString ? `${baseUrl}?${queryString}` : baseUrl;
  }, [utmSource, utmMedium, utmCampaign]);

  const handleCopyUrl = () => {
    navigator.clipboard.writeText(generatedUrl);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="page-enter space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-bold text-[var(--text-primary)]">Traffic Sources</h1>
        <p className="text-sm text-[var(--text-secondary)] mt-1">
          Understand where your visitors come from and track campaign performance
        </p>
      </div>

      {/* Top Row: Pie Chart + Detailed Table */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Pie Chart */}
        <Card padding="md">
          <h3 className="text-base font-semibold text-[var(--text-primary)] mb-2">
            Traffic Distribution
          </h3>
          <p className="text-sm text-[var(--text-secondary)] mb-4">
            {totalVisits.toLocaleString()} total visits this period
          </p>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={pieData}
                  cx="50%"
                  cy="50%"
                  innerRadius={70}
                  outerRadius={110}
                  paddingAngle={3}
                  dataKey="value"
                  stroke="none"
                >
                  {pieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip
                  contentStyle={{
                    backgroundColor: 'var(--bg-surface)',
                    borderColor: 'var(--border-default)',
                    borderRadius: '8px',
                    fontSize: '13px',
                    color: 'var(--text-primary)',
                  }}
                  formatter={(value: number, name: string) => [
                    `${value.toLocaleString()} visits`,
                    name,
                  ]}
                />
                <Legend
                  wrapperStyle={{ fontSize: '13px' }}
                  formatter={(value: string) => (
                    <span style={{ color: 'var(--text-secondary)' }}>{value}</span>
                  )}
                />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </Card>

        {/* Detailed Source Table */}
        <Card padding="md">
          <h3 className="text-base font-semibold text-[var(--text-primary)] mb-4">
            Source Breakdown
          </h3>
          <div className="space-y-3">
            {sources.map((source) => {
              const color = SOURCE_COLORS[source.source] || '#64748B';
              const trend = SOURCE_TRENDS[source.source] || 0;

              return (
                <div
                  key={source.source}
                  className="flex items-center gap-4 py-2.5 border-b border-[var(--border-subtle)] last:border-0"
                >
                  {/* Color dot + Source name */}
                  <div className="flex items-center gap-2.5 w-32 shrink-0">
                    <div
                      className="w-3 h-3 rounded-full shrink-0"
                      style={{ backgroundColor: color }}
                    />
                    <span className="text-sm font-medium text-[var(--text-primary)] truncate">
                      {source.source}
                    </span>
                  </div>

                  {/* Visits */}
                  <span className="text-sm font-semibold text-[var(--text-primary)] w-16 text-right shrink-0">
                    {source.visits.toLocaleString()}
                  </span>

                  {/* Percentage Bar */}
                  <div className="flex-1 min-w-0">
                    <div className="h-2.5 rounded-full bg-[var(--bg-elevated)] overflow-hidden">
                      <div
                        className="h-full rounded-full transition-all duration-700"
                        style={{
                          width: `${source.percentage}%`,
                          backgroundColor: color,
                        }}
                      />
                    </div>
                  </div>

                  {/* Percentage value */}
                  <span className="text-sm font-medium text-[var(--text-secondary)] w-12 text-right shrink-0">
                    {source.percentage}%
                  </span>
                </div>
              );
            })}
          </div>
        </Card>
      </div>

      {/* Link Performance Section */}
      <Card padding="md">
        <h3 className="text-base font-semibold text-[var(--text-primary)] mb-1">
          Link Performance
        </h3>
        <p className="text-sm text-[var(--text-secondary)] mb-4">
          Visit counts and trends by source compared to the previous period
        </p>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {sources.map((source) => {
            const color = SOURCE_COLORS[source.source] || '#64748B';
            const trend = SOURCE_TRENDS[source.source] || 0;

            return (
              <div
                key={source.source}
                className="flex items-center gap-3 p-3 rounded-lg border border-[var(--border-default)] bg-[var(--bg-surface)]"
              >
                <div
                  className="w-10 h-10 rounded-lg flex items-center justify-center shrink-0"
                  style={{ backgroundColor: `${color}15` }}
                >
                  <Globe className="w-5 h-5" style={{ color }} />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-[var(--text-primary)] truncate">
                    {source.source}
                  </p>
                  <p className="text-lg font-bold text-[var(--text-primary)]">
                    {source.visits.toLocaleString()}
                  </p>
                </div>
                <div className="shrink-0">
                  <TrendIndicator value={trend} />
                </div>
              </div>
            );
          })}
        </div>
      </Card>

      {/* UTM Builder Section */}
      <Card padding="lg">
        <div className="flex items-center gap-2.5 mb-1">
          <Link2 className="w-5 h-5 text-[var(--accent-text)]" />
          <h3 className="text-lg font-semibold text-[var(--text-primary)]">
            UTM Campaign Builder
          </h3>
        </div>
        <p className="text-sm text-[var(--text-secondary)] mb-5">
          Generate tracked URLs to measure campaign performance
        </p>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          {/* Source */}
          <div>
            <label className="block text-sm font-medium text-[var(--text-primary)] mb-1.5">
              Source
            </label>
            <input
              type="text"
              value={utmSource}
              onChange={(e) => setUtmSource(e.target.value)}
              placeholder="e.g. instagram"
              className="w-full px-4 py-2.5 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-surface)] text-[var(--text-primary)] placeholder:text-[var(--text-tertiary)] focus:outline-none focus:ring-2 focus:ring-[var(--accent)] focus:border-transparent"
            />
          </div>

          {/* Medium */}
          <div>
            <label className="block text-sm font-medium text-[var(--text-primary)] mb-1.5">
              Medium
            </label>
            <input
              type="text"
              value={utmMedium}
              onChange={(e) => setUtmMedium(e.target.value)}
              placeholder="e.g. bio_link"
              className="w-full px-4 py-2.5 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-surface)] text-[var(--text-primary)] placeholder:text-[var(--text-tertiary)] focus:outline-none focus:ring-2 focus:ring-[var(--accent)] focus:border-transparent"
            />
          </div>

          {/* Campaign */}
          <div>
            <label className="block text-sm font-medium text-[var(--text-primary)] mb-1.5">
              Campaign
            </label>
            <input
              type="text"
              value={utmCampaign}
              onChange={(e) => setUtmCampaign(e.target.value)}
              placeholder="e.g. spring_sale"
              className="w-full px-4 py-2.5 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-surface)] text-[var(--text-primary)] placeholder:text-[var(--text-tertiary)] focus:outline-none focus:ring-2 focus:ring-[var(--accent)] focus:border-transparent"
            />
          </div>
        </div>

        {/* Generated URL Preview */}
        <div className="mt-5">
          <label className="block text-sm font-medium text-[var(--text-primary)] mb-1.5">
            Generated URL
          </label>
          <div className="flex items-center gap-2">
            <div className="flex-1 px-4 py-2.5 text-sm font-mono rounded-lg border border-[var(--border-default)] bg-[var(--bg-elevated)] text-[var(--text-secondary)] overflow-x-auto whitespace-nowrap">
              {generatedUrl}
            </div>
            <Button
              variant="secondary"
              size="md"
              icon={
                copied ? (
                  <Check className="w-4 h-4 text-emerald-500" />
                ) : (
                  <Copy className="w-4 h-4" />
                )
              }
              onClick={handleCopyUrl}
            >
              {copied ? 'Copied' : 'Copy'}
            </Button>
          </div>
        </div>
      </Card>
    </div>
  );
}

